package main

import "fmt"

func main() {
	// Klasik for dongusu
	fmt.Println("1'den 5'e kadar:")
	for i := 1; i <= 5; i++ {
		fmt.Println("Sayi:", i)
	}

	// while gibi for kullanimi
	fmt.Println("\nGeri sayim:")
	counter := 5
	for counter > 0 {
		fmt.Println(counter)
		counter--
	}

	// range ile slice uzerinde dongu
	fmt.Println("\nMeyveler:")
	fruits := []string{"Elma", "Armut", "Muz", "Karpuz"}
	for index, fruit := range fruits {
		fmt.Println(index, "-", fruit)
	}

	// Sonsuz dongu + break
	fmt.Println("\nBreak ornegi:")
	n := 0
	for {
		if n >= 3 {
			break
		}
		fmt.Println("n =", n)
		n++
	}

	// continue ornegi
	fmt.Println("\nContinue ornegi (cift sayilari atla):")
	for i := 0; i < 6; i++ {
		if i%2 == 0 {
			continue
		}
		fmt.Println(i)
	}
}
